// Filter to only recent Anthropic verification emails.
// NOTE: simple output mode omits receivedDateTime -- treat missing as recent.
const items = $input.all();
const results = [];
for (const item of items) {
  const subject = (item.json.subject || '').toLowerCase();
  const from = (item.json.from && item.json.from.emailAddress && item.json.from.emailAddress.address || item.json.from || '').toLowerCase();
  const isAnthropicSender = from.includes('anthropic.com') || from.includes('claude.ai');
  const isLoginSubject = subject.includes('claude') || subject.includes('sign in') || subject.includes('secure link') || subject.includes('log in') || subject.includes('magic') || subject.includes('verify') || subject.includes('login') || subject.includes('authenticate');
  if (!isAnthropicSender && !isLoginSubject) continue;
  if (item.json.receivedDateTime || item.json.createdDateTime) {
    const receivedAt = new Date(item.json.receivedDateTime || item.json.createdDateTime);
    const ageMs = Date.now() - receivedAt.getTime();
    if (ageMs > 10 * 60 * 1000) continue;
  }
  if (!item.json.id) continue;
  results.push({ json: { id: item.json.id, subject: item.json.subject, receivedDateTime: item.json.receivedDateTime } });
}
return results;

// Extract magic link URL and/or 6-digit verification code from full email body.
const items = $input.all();
const results = [];
for (const item of items) {
  const bodyHtml = (item.json.body && item.json.body.content) || '';
  const bodyText = item.json.bodyPreview || '';
  const searchIn = bodyHtml + ' ' + bodyText;
  const plainText = bodyHtml.replace(/<[^>]+>/g, ' ').replace(/&amp;/g, '&').replace(/&nbsp;/g, ' ');
  let magicUrl = null;
  const patterns = [
    /https:\/\/claude\.ai\/magic-link[^\s"'<>)\\]+/i,
    /https:\/\/platform\.claude\.com\/magic-link[^\s"'<>)\\]+/i,
    /https:\/\/claude\.ai\/verify[^\s"'<>)\\]+/i,
    /https:\/\/platform\.claude\.com\/[^\s"'<>)\\]+/i,
    /https:\/\/claude\.com\/[^\s"'<>)\\]*(?:magic|verify|link|token)[^\s"'<>)\\]+/i,
    /https:\/\/[^\s"'<>)\\]+\.claude\.(?:ai|com)\/[^\s"'<>)\\]+/i,
  ];
  for (const pattern of patterns) {
    const m = searchIn.match(pattern);
    if (m) { magicUrl = m[0].replace(/&amp;/g, '&').replace(/[.,;!?]+$/, ''); break; }
  }
  let directCode = null;
  const codePatterns = [
    /verification\s+code[:\s]+([0-9]{6})\b/i,
    /use\s+code[:\s]+([0-9]{6})\b/i,
    /code[:\s]+([0-9]{6})\b/i,
  ];
  for (const cp of codePatterns) {
    const cm = plainText.match(cp);
    if (cm) { directCode = cm[1]; break; }
  }
  if (magicUrl) results.push({ json: { url: magicUrl, directCode: directCode, subject: item.json.subject, messageId: item.json.id } });
  else if (directCode) results.push({ json: { url: directCode, directCode: directCode, subject: item.json.subject, messageId: item.json.id } });
}
return results.length ? results : [];

